-- ── currencylayer ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Currencylayer is a REST API that provides real-time and historical exchange rate data for 168 world currencies plus precious metals, delivered in JSON format. It is a product of apilayer, an API marketplace company founded in Vienna, Austria in 2015 that was itself acquired by Idera Inc. in January 2021. Currencylayer targets developers building currency conversion into commercial and internal applications.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription with tiered monthly request limits and update-frequency gating$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; paid plans start at 13.99 USD per month$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$11-50 employees (apilayer, part of Idera Inc.)$q$, company_size),
  headquarters = COALESCE($q$Vienna, Austria$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Currencylayer Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Currencylayer delivers real-time and historical exchange rates for 168 currencies via REST API. Compare 2026 pricing plans, features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Currencylayer is a currency exchange rate API that supplies real-time and historical foreign exchange data for 168 world currencies plus precious metals, formatted as portable JSON compatible with virtually any programming language or framework. It was founded in 2015 by brothers Julian and Paul Zehetmayr in Vienna, Austria, as one of the flagship products of apilayer, a company that builds and sells a portfolio of developer-facing data APIs. In January 2021, apilayer itself was acquired by Idera, Inc., a portfolio company known for owning a range of developer and database tools, which means Currencylayer today operates as a product line inside a larger, private-equity-backed software group rather than as a standalone startup. The API sources spot exchange rate data from multiple major forex data providers, validating and processing the feed before delivery, with refresh frequency gated by subscription tier: the free plan updates once daily, the Basic plan updates hourly, the Professional plan updates every 10 minutes, and the top Business Plus plan updates within a 60-second market window. Currencylayer's endpoints include live rates, historical rates reaching back roughly 19 years (to 1999 in the company's own documentation), currency conversion, time-frame queries between two dates, and currency-change or fluctuation queries, all keyed to a default USD base on lower tiers with more flexible base currency support on paid tiers. Pricing as of 2026 is structured as: a free tier for evaluation and light use; a Basic plan at 13.99 USD per month (or 161.99 USD per year, roughly a 10 percent discount) offering commercial usage rights and up to 10,000 requests per month; a Professional plan at 52.99 USD per month (or 629.99 USD per year, about 12.5 percent off) with premium features and up to 100,000 monthly requests; and a Business Plus plan at 84.99 USD per month (or 1,019.99 USD per year, about 15 percent off) unlocking every feature and up to 500,000 monthly requests. Currencylayer is also distributed through the RapidAPI marketplace as an alternative purchasing channel. Because it is one of the older, more established players in the currency-API category and carries the apilayer and Idera brand behind it, Currencylayer is often positioned by third parties as a more enterprise-credible option than newer bootstrapped alternatives, though it is priced somewhat higher at comparable usage tiers than challengers such as CurrencyFreaks. Typical customers are software teams building e-commerce, fintech, travel, ERP, or accounting products that require dependable multi-currency conversion, historical rate auditing, or fluctuation reporting. Buyers evaluating Currencylayer in 2026 should weigh its longer track record and corporate backing against its higher per-tier pricing relative to some newer entrants in the same space.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f064b584-3ba5-4055-94d3-094bbe07b335';

