-- ── CurrencyScoop ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CurrencyScoop was a REST API offering real-time and historical exchange rate data for 168 world currencies in JSON format. As of 2026, the currencyscoop.com domain redirects to CurrencyBeacon, indicating the product has been rebranded and consolidated under the CurrencyBeacon name, which now serves as the active successor product for the same underlying currency data service.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription with tiered monthly request limits (now operated under the CurrencyBeacon brand)$q$, pricing_model),
  starting_price = COALESCE($q$Free developer sandbox available; paid plans start at approximately 10 USD per month under the successor CurrencyBeacon brand$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CurrencyScoop Review 2026: Status, Pricing and CurrencyBeacon Rebrand$q$, seo_title),
  seo_meta_description = COALESCE($q$CurrencyScoop offered real-time and historical exchange rate data via REST API. Learn about its 2026 status, rebrand to CurrencyBeacon, and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CurrencyScoop was positioned as a developer-friendly REST API delivering real-time and historical currency exchange rate data for 168 world currencies, returned in a universally usable JSON format compatible with any programming language or application. The service sourced spot exchange rate data from multiple major forex data providers, central banks, and commercial vendors, validating and processing it before delivery, and historically offered a free trial tier providing up to 5,000 requests per day after email verification, with no credit card required to start. As of 2026, the official currencyscoop.com domain no longer hosts the original CurrencyScoop product directly; instead it performs a permanent redirect to currencybeacon.com, a currency data API business that describes itself as having started over a decade ago as a currency log before evolving into its current form, and that now says it serves more than 100,000 businesses and developers. This redirect pattern, combined with third-party integration platforms (such as Pipedream, Composio, and Relevance AI) that still reference 'CurrencyScoop' as an app name while pointing to what is functionally the same currency-data service, strongly suggests that CurrencyScoop was rebranded or consolidated into CurrencyBeacon rather than shut down outright, though the exact corporate mechanics of that transition (acquisition, internal rebrand, or asset transfer) are not clearly documented in public sources. Because of this, anyone researching 'CurrencyScoop' in 2026 should treat CurrencyBeacon as the current, actively maintained product to evaluate for real usage. Under the CurrencyBeacon brand, the currency data API is offered on a tiered subscription model: a free Developer Sandbox plan providing 5,000 requests with hourly rate updates; a Basic plan at 10 USD per month (or 100 USD per year) providing 50,000 requests with rates refreshed every 15 minutes; a Startup plan at 99 USD per month (or 900 USD per year) providing 500,000 requests with rates refreshed every minute; and a Professional plan at 599 USD per month (or 6,500 USD per year) providing 2,000,000 requests with real-time rate updates. The product also exposes an MCP (Model Context Protocol) server so AI agents and LLM-based tools can query exchange rates directly, and REST API calls share the same usage quota as MCP tool calls. Because the original CurrencyScoop brand, founding details, headquarters, and team size are not clearly documented in current public sources following the transition to CurrencyBeacon, those specific facts should be treated as unconfirmed rather than assumed. Typical use cases for this category of API, both under the old CurrencyScoop name and its CurrencyBeacon successor, include e-commerce currency conversion, fintech reporting, travel price localization, and increasingly, giving AI agents a live data source for currency-related questions via the MCP integration.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd2bd90e0-5e3f-4755-9bdf-dba19c114207';

