-- ── Customer Lobby ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Customer Lobby is a marketing and reputation platform for home and field service businesses, such as HVAC, plumbing, electrical, and carpet cleaning companies, that ties marketing spend to sales results and automates personalized customer outreach. Founded in 2007 by Ted Paff in the San Francisco Bay Area, it was later acquired by EverCommerce and today operates as part of EverCommerce's EverPro division of home-service software brands.$q$, short_description),
  pricing_model = COALESCE($q$Subscription software with plan-based pricing$q$, pricing_model),
  starting_price = COALESCE($q$Plans have historically started around 299 USD per month for the Pro Marketing tier$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE($q$Not publicly disclosed as a standalone entity (operates as a brand within EverCommerce, a publicly traded company)$q$, company_size),
  headquarters = COALESCE($q$Denver, Colorado, United States (as an EverCommerce/EverPro brand; originally founded in the Oakland/Berkeley, California area)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Customer Lobby Review 2026: Pricing, Features, EverCommerce Status$q$, seo_title),
  seo_meta_description = COALESCE($q$Customer Lobby helps home service businesses generate repeat business. See 2026 pricing, features, EverCommerce ownership, and pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Customer Lobby is a marketing automation and customer retention platform built specifically for local and home-service businesses, including HVAC, plumbing, electrical, carpet cleaning, home improvement, and auto service companies. It was founded in 2007 by Ted Paff, who self-financed and built the company before eventually selling it. As of 2026, Customer Lobby operates as a brand within EverCommerce (NASDAQ: EVCM), a publicly traded, multi-brand vertical software company, specifically under EverCommerce's EverPro division, which bundles trade-specific software for home and field service professionals and is described as trusted by more than 350,000 home and field service businesses across the EverPro portfolio. This means Customer Lobby is no longer an independently operated startup; its product roadmap, support infrastructure, and go-to-market motion are aligned with EverCommerce's broader home-services software strategy, which also includes sibling EverPro brands. The core Customer Lobby product connects to a business's existing invoicing or job-management system and uses that transaction data to trigger personalized, multi-channel marketing messages, print mailers, email, and other outreach aimed at both past customers (to drive repeat business) and prospective customers identified through predictive targeting. The platform emphasizes marketing accountability: it explicitly ties marketing dollars spent to sales results generated, which is a differentiator against generic email marketing tools that do not close the loop back to revenue. Key functional areas include Prospect Marketing, which uses predictive modeling to identify likely-to-convert local prospects, and Customer Marketing, which automates retention campaigns to existing customers, largely running with low day-to-day maintenance once configured. Historical pricing data shows plans starting around 299 USD per month for a Pro Marketing tier, though EverCommerce and EverPro do not always publish transparent, self-serve pricing, and prospective buyers are typically routed through a sales demo request rather than a public price list, which is common in the home-services SaaS category (a sibling product, LobbyCentral, is also part of the same company's portfolio and has separate published pricing). Customer Lobby's target buyer is an owner or marketing manager at a small-to-midsize home or field service business who wants to reduce reliance on expensive paid lead generation channels and instead extract more repeat and referral revenue from an existing customer base. Given the EverCommerce ownership structure, buyers should expect the product to be positioned and cross-sold alongside other EverPro tools (such as field service management, invoicing, and review-generation software) rather than sold purely as a standalone reputation-management point solution.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd45f9431-9e0c-4ef3-bcf4-e8d33c882ffc';

