-- ── CustomJS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CustomJS is a cloud platform that lets developers and no-code builders run custom JavaScript and Node.js functions as serverless API endpoints, alongside tools for PDF generation, screenshots, form building, web scraping, and email webhooks. It is operated by TechnologyCircle GmbH, headquartered in Hamburg, Germany, and integrates directly with automation platforms like Make, n8n, Zapier, and Power Automate as well as raw API access.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription with tiered daily request limits$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; paid plans start at 9 USD per month$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (small team)$q$, company_size),
  headquarters = COALESCE($q$Hamburg, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CustomJS Review 2026: Pricing, Features and Use Cases$q$, seo_title),
  seo_meta_description = COALESCE($q$CustomJS runs custom JavaScript as serverless endpoints for PDFs, forms, scraping and more. See 2026 pricing plans, features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CustomJS is a cloud execution platform that allows developers and no-code automation builders to run custom JavaScript and Node.js code as hosted, callable API endpoints without managing servers. It is built and operated by TechnologyCircle GmbH, a company headquartered in Hamburg, Germany. Rather than positioning itself purely as a generic serverless function host, CustomJS bundles several purpose-built capabilities around its JavaScript execution engine: full NPM package support for Node.js code, HTML-to-PDF document generation, website screenshot capture, static page and form hosting, a drag-and-drop form builder, headless forms for embedding in other sites, a mail hook feature that forwards incoming email to a webhook, a web scraper API for extracting data from pages, and a Model Context Protocol (MCP) server so AI agents can call CustomJS functions as tools. The platform is explicitly designed to plug the gaps that no-code automation tools leave behind: it integrates directly with Make (formerly Integromat), n8n, Microsoft Power Automate, and Zapier, letting non-developers or citcitzen-developer teams drop in a snippet of custom JavaScript logic in the middle of an otherwise visual automation workflow, in addition to being callable via a direct REST API for traditional developers. Pricing is structured around a small number of straightforward monthly tiers, each billed either monthly or annually (with roughly 25 percent savings on annual billing). The Free plan allows 20 requests per day, 3 forms with up to 500 monthly responses, 1 mail hook with up to 10 daily incoming emails, and 5 hosted pages, with email-only support and no credit card required to start. The Pro plan, at 9 USD per month, raises limits to 100 requests per day, 9 forms with 2,000 monthly responses, 3 mail hooks with 50 daily incoming emails, 15 hosted pages, and 1 custom domain. The Ultra plan, at 29 USD per month, further raises limits to 500 requests per day, 29 forms with 6,000 monthly responses, 19 mail hooks with 250 daily incoming emails, 40 hosted pages, and adds direct JavaScript coding support from the CustomJS team. The Mega plan, at 99 USD per month, is the top published tier, offering 5,000 requests per day, 59 forms with 30,000 monthly responses, 49 mail hooks with 1,000 daily incoming emails, 100 hosted pages, and full support including scheduled video call assistance. All paid plans remove watermarks from generated PDFs, which is a common consideration for teams generating client-facing documents. Because CustomJS sits at the intersection of a serverless function runtime and a no-code automation utility belt, its most common users are automation-focused teams (agencies and internal ops teams building Make or n8n workflows), solo developers who need quick custom logic without standing up their own cloud infrastructure, and AI/agent builders who want a way to give an LLM agent the ability to execute arbitrary JavaScript, generate a PDF, or scrape a webpage as a callable tool.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '801fe2d5-0a0e-4153-b330-c3eb6d4148a9';

