INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61188af5-1198-422b-88a6-c3d5d9272337', $q$What is CurrencyFreaks used for$q$, $q$It is used to fetch live and historical currency exchange rates through a REST API, typically to power price conversion, invoicing, and financial reporting features in software applications.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61188af5-1198-422b-88a6-c3d5d9272337', $q$Does CurrencyFreaks have a free plan$q$, $q$Yes, it offers a free plan with 1,000 monthly API calls, daily rate updates, and no credit card requirement.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61188af5-1198-422b-88a6-c3d5d9272337', $q$How many currencies does CurrencyFreaks support$q$, $q$It supports 1,026 currency codes in total, covering roughly 166 to 174 fiat currencies, 4 precious metals, and several hundred cryptocurrencies.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61188af5-1198-422b-88a6-c3d5d9272337', $q$How far back does CurrencyFreaks historical data go$q$, $q$Historical exchange rate data is available going back to 1984 on eligible plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61188af5-1198-422b-88a6-c3d5d9272337', $q$What is the cheapest paid CurrencyFreaks plan$q$, $q$The Starter plan costs 9.99 USD per month and includes 15,000 requests with hourly rate updates.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61188af5-1198-422b-88a6-c3d5d9272337', $q$Who operates CurrencyFreaks$q$, $q$CurrencyFreaks is operated by JFreaks, a small, bootstrapped, customer-funded company headquartered in Lahore, Pakistan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61188af5-1198-422b-88a6-c3d5d9272337', $q$Does CurrencyFreaks support cryptocurrency rates$q$, $q$Yes, several hundred cryptocurrencies are included alongside fiat currencies and precious metals.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61188af5-1198-422b-88a6-c3d5d9272337', $q$Is CurrencyFreaks suitable for enterprise use$q$, $q$It offers a custom Enterprise plan with 60-second updates and access to all endpoints, though the company does not publish formal enterprise SLAs.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('61188af5-1198-422b-88a6-c3d5d9272337', $q$E-commerce checkout localization$q$, $q$Online stores use the API to display and calculate prices in a shopper's local currency at checkout.$q$, $q$E-commerce developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('61188af5-1198-422b-88a6-c3d5d9272337', $q$Fintech and accounting dashboards$q$, $q$Financial software pulls live and historical rates to reconcile multi-currency transactions and reporting.$q$, $q$Fintech and accounting teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('61188af5-1198-422b-88a6-c3d5d9272337', $q$Travel and booking platforms$q$, $q$Booking sites convert prices into a traveler's home currency using real-time exchange data.$q$, $q$Travel technology teams$q$, 2);
