INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('61188af5-1198-422b-88a6-c3d5d9272337', $q$Growth$q$, $q$49.99 USD$q$, $q$monthly$q$, NULL, $q$["150,000 requests per month","10-minute rate updates","IP-to-currency detection","Premium support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('61188af5-1198-422b-88a6-c3d5d9272337', $q$Professional$q$, $q$99.99 USD$q$, $q$monthly$q$, NULL, $q$["550,000 requests per month","60-second rate updates","Time series and fluctuation data","Premium support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('61188af5-1198-422b-88a6-c3d5d9272337', $q$Enterprise$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["60-second rate updates","Access to all endpoints","Custom volume and support terms"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('61188af5-1198-422b-88a6-c3d5d9272337', $q$what-is-currencyfreaks$q$, $q$What is CurrencyFreaks$q$, 2, ARRAY[$q$CurrencyFreaks is a currency exchange rate API designed for developers who need to embed live or historical foreign exchange data into websites, mobile apps, or backend financial systems. It exposes a single, consistent REST endpoint style that can return live rates, historical rates, converted amounts, and time-series data depending on the query parameters supplied.$q$, $q$The service is built and operated by JFreaks, a small independent software company. Unlike some competitors that are owned by larger data or API conglomerates, CurrencyFreaks has remained self-funded and bootstrapped since its 2018 launch, which the company positions as a reason it can offer aggressive pricing relative to larger incumbents.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('61188af5-1198-422b-88a6-c3d5d9272337', $q$data-coverage-and-accuracy$q$, $q$Data coverage and update frequency$q$, 2, ARRAY[$q$CurrencyFreaks covers 1,026 currency codes in total, spanning roughly 166 to 174 fiat currencies, 4 precious metals, and several hundred cryptocurrencies. Historical data is available going back to 1984 on applicable plans, which is deeper than many competing free-tier APIs.$q$, $q$Update frequency is tied to the subscription tier: free and entry paid plans refresh hourly or daily, while higher tiers refresh every 10 minutes, and the top commercial tiers refresh every 60 seconds for near-real-time accuracy.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('61188af5-1198-422b-88a6-c3d5d9272337', $q$who-should-use-it$q$, $q$Who should use CurrencyFreaks$q$, 2, ARRAY[$q$CurrencyFreaks fits teams that want a straightforward, affordably priced exchange rate feed without committing to an enterprise data vendor. It is a common choice for indie developers, small e-commerce shops, and startups building multi-currency pricing or invoicing features.$q$, $q$Larger organizations with strict SLA, compliance, or uptime requirements may still want to evaluate CurrencyFreaks alongside larger providers before committing, since the company is small and does not publish formal enterprise SLAs on its marketing pages.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$168 world currencies plus metals$q$, $q$Covers a broad set of fiat currencies and precious metals from a single API.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$Live exchange rates$q$, $q$Delivers real-time spot rates sourced from multiple major forex data providers.$q$, 1);
