INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$What is Currencylayer used for$q$, $q$It is used by developers to retrieve real-time and historical currency exchange rates for use in commercial and internal software applications.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$Who owns Currencylayer$q$, $q$Currencylayer is a product of apilayer, which was acquired by Idera, Inc. in January 2021.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$How much does Currencylayer cost$q$, $q$Paid plans start at 13.99 USD per month for the Basic plan, with Professional at 52.99 USD per month and Business Plus at 84.99 USD per month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$Does Currencylayer have a free tier$q$, $q$Yes, it offers a free plan with daily rate updates for evaluation and light usage.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$How many currencies does Currencylayer support$q$, $q$It supports 168 world currencies plus precious metals.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$How often are Currencylayer exchange rates updated$q$, $q$Update frequency depends on plan: daily on the free plan, hourly on Basic, every 10 minutes on Professional, and every 60 seconds on Business Plus.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$How far back does Currencylayer historical data go$q$, $q$The API provides historical exchange rate data reaching back roughly 19 years, to 1999.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$Is Currencylayer available on RapidAPI$q$, $q$Yes, Currencylayer is also distributed through the RapidAPI marketplace as an alternative access point.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$E-commerce multi-currency pricing$q$, $q$Online retailers convert product prices into a shopper's local currency in real time.$q$, $q$E-commerce and marketplace developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$Financial auditing and reporting$q$, $q$Finance teams use historical rate data to reconcile past multi-currency transactions.$q$, $q$Accounting and finance software teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$Travel and booking price conversion$q$, $q$Travel platforms display fares and rates converted into a customer's home currency.$q$, $q$Travel technology teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$Free$q$, $q$0 USD$q$, $q$monthly$q$, NULL, $q$["Daily rate updates","Limited monthly requests","Access to core live rate endpoint"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$Basic$q$, $q$13.99 USD monthly or 161.99 USD yearly$q$, $q$monthly or annual$q$, NULL, $q$["Up to 10,000 requests per month","Commercial use permitted","Hourly rate updates"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$Professional$q$, $q$52.99 USD monthly or 629.99 USD yearly$q$, $q$monthly or annual$q$, NULL, $q$["Up to 100,000 requests per month","10-minute rate updates","Premium features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$Business Plus$q$, $q$84.99 USD monthly or 1,019.99 USD yearly$q$, $q$monthly or annual$q$, NULL, $q$["Up to 500,000 requests per month","60-second rate updates","Every feature unlocked"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$what-is-currencylayer$q$, $q$What is Currencylayer$q$, 2, ARRAY[$q$Currencylayer is a REST API delivering real-time and historical foreign exchange rate data for 168 world currencies plus select precious metals. It is one of the original products offered by apilayer, an Austrian API marketplace company, and has been operating since 2015.$q$, $q$The API returns data in JSON format designed to be compatible with any modern application stack, and it is commonly used as a drop-in data source for currency conversion features in commercial software.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$ownership-and-company-background$q$, $q$Ownership and company background$q$, 2, ARRAY[$q$Currencylayer was founded by Julian and Paul Zehetmayr as part of apilayer, headquartered in Vienna, Austria. In January 2021, apilayer was acquired by Idera, Inc., a company that owns a broad portfolio of developer and database tooling brands.$q$, $q$This means Currencylayer is no longer an independent startup product but rather a business unit inside a larger software holding group, which can offer buyers more stability but also means product direction is set at the portfolio level.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f064b584-3ba5-4055-94d3-094bbe07b335', $q$pricing-tiers-explained$q$, $q$How Currencylayer pricing tiers work$q$, 2, ARRAY[$q$Currencylayer pricing scales along two axes: monthly request volume and rate refresh frequency. The free plan is limited to daily-updated rates, while paid tiers unlock progressively faster refresh windows down to 60 seconds on the top Business Plus plan.$q$, $q$Annual billing offers a discount of roughly 10 to 15 percent depending on the tier, which can meaningfully reduce cost for teams with predictable, ongoing usage.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2bd90e0-5e3f-4755-9bdf-dba19c114207', $q$168 world currencies$q$, $q$Covered real-time and historical exchange rate data for 168 fiat currencies.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2bd90e0-5e3f-4755-9bdf-dba19c114207', $q$JSON REST format$q$, $q$Delivered exchange rate data in a universally compatible JSON structure.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2bd90e0-5e3f-4755-9bdf-dba19c114207', $q$Free trial with 5,000 daily requests$q$, $q$Allowed developers to evaluate the API without a credit card via email verification.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2bd90e0-5e3f-4755-9bdf-dba19c114207', $q$Historical and time-series data$q$, $q$Supported historical rate lookups and time-series queries for trend analysis.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2bd90e0-5e3f-4755-9bdf-dba19c114207', $q$RapidAPI marketplace availability$q$, $q$Was also distributed through RapidAPI as an alternative purchasing channel.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2bd90e0-5e3f-4755-9bdf-dba19c114207', $q$Redirect to CurrencyBeacon successor$q$, $q$The original domain now forwards to CurrencyBeacon, which offers an equivalent, actively maintained service.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2bd90e0-5e3f-4755-9bdf-dba19c114207', $q$MCP server support (via successor)$q$, $q$CurrencyBeacon, the successor product, exposes a Model Context Protocol server for AI agent integrations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d2bd90e0-5e3f-4755-9bdf-dba19c114207', $q$Cryptocurrency conversion (via successor)$q$, $q$The successor CurrencyBeacon product extends coverage to cryptocurrency conversion alongside fiat rates.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d2bd90e0-5e3f-4755-9bdf-dba19c114207', $q$Simple, well-documented REST API design carried over to the successor product$q$, 0);
